# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import pymysql
import json

def lambda_handler(event, context):
    # Database connection configuration
    db_config = {
        'host': 'your-rds-endpoint',
        'user': 'your-username',
        'password': 'your-password',
        'database': 'your-database'
    }
    
    # Extract search parameters from the API Gateway event
    query_params = event.get('queryStringParameters', {})
    product_name = query_params.get('name')
    min_price = query_params.get('minPrice')
    max_price = query_params.get('maxPrice')
    
    # Construct SQL query dynamically based on provided parameters
    sql_query = "SELECT * FROM products WHERE 1=1"
    params = []
    
    if product_name:
        sql_query += " AND name LIKE %s"
        params.append(f"%{product_name}%")
    
    if min_price:
        sql_query += " AND price >= %s"
        params.append(float(min_price))
    
    if max_price:
        sql_query += " AND price <= %s"
        params.append(float(max_price))
    
    # Connect to the RDS MySQL database
    connection = pymysql.connect(**db_config)
    cursor = connection.cursor()
    
    try:
        # Execute the SQL query
        cursor.execute(sql_query, params)
        
        # Fetch all results
        results = cursor.fetchall()
        
        # Convert results to a list of dictionaries
        columns = [desc[0] for desc in cursor.description]
        products = [dict(zip(columns, row)) for row in results]
        
        return {
            'statusCode': 200,
            'body': json.dumps(products)
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
    finally:
        # Close the database connection
        cursor.close()
        connection.close()